const { ApolloServer, gql, AuthenticationError, ForbiddenError } = require('apollo-server');
const { PubSub } = require('graphql-subscriptions');
const { createServer } = require('http');
const { ApolloServerPluginDrainHttpServer } = require('apollo-server-core');
const { makeExecutableSchema } = require('@graphql-tools/schema');
const { WebSocketServer } = require('ws');
const { useServer } = require('graphql-ws/lib/use/ws');

const pubsub = new PubSub();

const chatRooms = new Map();
const messages = new Map();
const userSessions = new Map();
const roomAccessControl = new Map();

const typeDefs = gql`
  type Message {
    id: ID!
    roomId: ID!
    content: String!
    sender: String!
    timestamp: String!
  }

  type ChatRoom {
    id: ID!
    name: String!
    messages: [Message!]!
  }

  type Query {
    chatRoom(id: ID!): ChatRoom
    messages(roomId: ID!, limit: Int): [Message!]!
  }

  type Mutation {
    createRoom(name: String!): ChatRoom!
    sendMessage(roomId: ID!, content: String!): Message!
    authenticate(userId: String!, token: String!): String!
    grantRoomAccess(roomId: ID!, userId: String!): Boolean!
  }

  type Subscription {
    messageSent(roomId: ID!): Message!
  }
`;

function validateInput(input, maxLength = 1000) {
  if (!input || typeof input !== 'string') {
    throw new Error('Invalid input');
  }
  if (input.length > maxLength) {
    throw new Error(`Input exceeds maximum length of ${maxLength}`);
  }
  return input.trim();
}

function authenticateUser(context) {
  const authHeader = context.req?.headers?.authorization || context.connectionParams?.authorization;
  
  if (!authHeader) {
    throw new AuthenticationError('Authentication required');
  }

  const token = authHeader.replace('Bearer ', '');
  const userId = userSessions.get(token);
  
  if (!userId) {
    throw new AuthenticationError('Invalid or expired token');
  }
  
  return userId;
}

function authorizeRoomAccess(userId, roomId) {
  const roomAccess = roomAccessControl.get(roomId);
  
  if (!roomAccess) {
    roomAccessControl.set(roomId, new Set([userId]));
    return true;
  }
  
  if (!roomAccess.has(userId)) {
    throw new ForbiddenError('Access denied to this chat room');
  }
  
  return true;
}

const resolvers = {
  Query: {
    chatRoom: (_, { id }, context) => {
      const userId = authenticateUser(context);
      authorizeRoomAccess(userId, id);
      
      const validatedId = validateInput(id, 100);
      return chatRooms.get(validatedId);
    },
    messages: (_, { roomId, limit = 50 }, context) => {
      const userId = authenticateUser(context);
      authorizeRoomAccess(userId, roomId);
      
      const validatedRoomId = validateInput(roomId, 100);
      const validatedLimit = Math.min(Math.max(1, limit || 50), 100);
      
      const roomMessages = messages.get(validatedRoomId) || [];
      return roomMessages.slice(-validatedLimit);
    },
  },
  Mutation: {
    authenticate: (_, { userId, token }) => {
      const validatedUserId = validateInput(userId, 100);
      const validatedToken = validateInput(token, 500);
      
      const sessionToken = `session_${Date.now()}_${Math.random()}`;
      userSessions.set(sessionToken, validatedUserId);
      
      return sessionToken;
    },
    createRoom: (_, { name }, context) => {
      const userId = authenticateUser(context);
      
      const validatedName = validateInput(name, 200);
      const roomId = `room_${Date.now()}_${Math.random()}`;
      
      const room = {
        id: roomId,
        name: validatedName,
        messages: [],
      };
      
      chatRooms.set(roomId, room);
      messages.set(roomId, []);
      
      roomAccessControl.set(roomId, new Set([userId]));
      
      return room;
    },
    grantRoomAccess: (_, { roomId, userId: targetUserId }, context) => {
      const userId = authenticateUser(context);
      
      const validatedRoomId = validateInput(roomId, 100);
      const validatedTargetUserId = validateInput(targetUserId, 100);
      
      authorizeRoomAccess(userId, validatedRoomId);
      
      const roomAccess = roomAccessControl.get(validatedRoomId);
      if (roomAccess) {
        roomAccess.add(validatedTargetUserId);
        return true;
      }
      
      return false;
    },
    sendMessage: (_, { roomId, content }, context) => {
      const userId = authenticateUser(context);
      authorizeRoomAccess(userId, roomId);
      
      const validatedRoomId = validateInput(roomId, 100);
      const validatedContent = validateInput(content, 5000);
      
      if (!chatRooms.has(validatedRoomId)) {
        throw new Error('Chat room not found');
      }
      
      const message = {
        id: `msg_${Date.now()}_${Math.random()}`,
        roomId: validatedRoomId,
        content: validatedContent,
        sender: userId,
        timestamp: new Date().toISOString(),
      };
      
      const roomMessages = messages.get(validatedRoomId) || [];
      roomMessages.push(message);
      messages.set(validatedRoomId, roomMessages);
      
      pubsub.publish(`MESSAGE_SENT_${validatedRoomId}`, { messageSent: message });
      
      return message;
    },
  },
  Subscription: {
    messageSent: {
      subscribe: (_, { roomId }, context) => {
        const userId = authenticateUser(context);
        authorizeRoomAccess(userId, roomId);
        
        const validatedRoomId = validateInput(roomId, 100);
        
        if (!chatRooms.has(validatedRoomId)) {
          throw new Error('Chat room not found');
        }
        
        return pubsub.asyncIterator(`MESSAGE_SENT_${validatedRoomId}`);
      },
    },
  },
};

async function startServer() {
  const schema = makeExecutableSchema({ typeDefs, resolvers });
  
  const httpServer = createServer();
  
  const wsServer = new WebSocketServer({
    server: httpServer,
    path: '/graphql',
  });
  
  const serverCleanup = useServer({
    schema,
    context: (ctx) => {
      return {
        connectionParams: ctx.connectionParams,
      };
    },
    onConnect: async (ctx) => {
      const authHeader = ctx.connectionParams?.authorization;
      if (!authHeader) {
        throw new Error('Authentication required for subscriptions');
      }
      return true;
    },
  }, wsServer);
  
  const server = new ApolloServer({
    schema,
    context: ({ req }) => ({ req }),
    plugins: [
      ApolloServerPluginDrainHttpServer({ httpServer }),
      {
        async serverWillStart() {
          return {
            async drainServer() {
              await serverCleanup.dispose();
            },
          };
        },
      },
    ],
  });
  
  await server.start();
  server.applyMiddleware({ app: httpServer });
  
  const PORT = 4000;
  httpServer.listen(PORT, () => {
    console.log(`Server ready at http://localhost:${PORT}${server.graphqlPath}`);
    console.log(`Subscriptions ready at ws://localhost:${PORT}${server.graphqlPath}`);
  });
}

startServer().catch(console.error);